checker_dsl:
EXISTS (`method call MC`) {
  AND {
    EXISTS (`string package`, `string type`, `int idx`) {
      AND {
        OR {
          AND {
            (`package is "java.util"`),
            (`type is "Collection"`),
            (`MC callee signature is "remove(java.lang.Object)"`),
            (`idx is 0`)
          },
          AND {
            (`package is "java.util"`),
            (`type is "Deque"`),
            (`MC callee signature is "removeFirstOccurrence(java.lang.Object)"`),
            (`idx is 0`)
          },
          AND {
            (`package is "java.util"`),
            (`type is "Deque"`),
            (`MC callee signature is "removeLastOccurrence(java.lang.Object)"`),
            (`idx is 0`)
          },
          AND {
            (`package is "java.util"`),
            (`type is "Dictionary"`),
            (`MC callee signature is "remove(java.lang.Object)"`),
            (`idx is 0`)
          },
          AND {
            (`package is "java.util"`),
            (`type is "Map"`),
            (`MC callee signature is "remove(java.lang.Object)"`),
            (`idx is 0`)
          },
          AND {
            (`package is "java.util"`),
            (`type is "Map"`),
            (`MC callee signature is "remove(java.lang.Object,java.lang.Object)"`),
            (`idx is 0`)
          },
          AND {
            (`package is "java.util"`),
            (`type is "Map"`),
            (`MC callee signature is "remove(java.lang.Object,java.lang.Object)"`),
            (`idx is 1`)
          },
          AND {
            (`package is "java.util"`),
            (`type is "Vector"`),
            (`MC callee signature is "removeElement(java.lang.Object)"`),
            (`idx is 0`)
          }
        },
        EXISTS (`RefType declaringType`) {
          AND {
            (`declaringType is MC callee declaring type`),
            EXISTS (`RefType supertype`) {
              AND {
                (`supertype is a source supertype of declaringType (transitive closure)`),
                (`supertype source declaration has qualified name package and type`)
              }
            }
          }
        },
        (`MC callee parameter at index idx has type TypeObject`)
      }
    },
    EXISTS (`RefType elementType`, `RefType argType`, `int idx`) {
      AND {
        (`elementType is receiver element type at index idx`),
        (`argType is argument type at index idx`),
        NOT {
          (`elementType and argType have type intersection`)
        }
      }
    }
  }
}
